def read_lines(lines):
    for line in lines:        # imagine a huge file
        yield line.strip()

def chain(*iterables):
    for it in iterables:
        yield from it          # delegate to each iterable

cleaned = read_lines([" a ", "b\n"])
print(list(chain(cleaned, ["c"])))   # ['a', 'b', 'c']

def stream_completion(text):
    for word in text.split():
        yield word + " "        # pretend each chunk arrives from the API

buffer = ""
for chunk in stream_completion("Generative AI streams tokens"):
    buffer += chunk
    print(chunk, end="")        # render incrementally
print("\n[done]", len(buffer), "chars")
